// FINAL node - read explicitly from Upload media
const workflowInput = $('When Executed by Another Workflow').item.json;
const upload = $('Upload media').first()?.json;     // <- force source
const errorIn = $input.first()?.json;               // optional: keep for error passthrough

if (upload?.id || upload?.video_media_id) {
  return [{ json: { video_media_id: upload.id || upload.video_media_id } }];
}

if (errorIn?.ugc_error === true) {
  return [{ json: { success: false, ugc_error: true, error_message: errorIn.error_message, clientId: errorIn.clientId } }];
}

return [{ json: { success: false, error_message: '❌ Video processing failed. Please try again.', clientId: workflowInput.clientId, ugc_error: false } }];

